import React, { useState } from 'react';

export default function ExpertLogin({ onLogin }) {

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleLogin = async (e) => {

    e.preventDefault();

    try {

      const response = await fetch(
        'http://localhost/farmer-portal-backend/expert_login.php',
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({
            email,
            password
          })
        }
      );

      const result = await response.json();

      if (result.status === 'success') {

        localStorage.setItem(
          'expert',
          JSON.stringify(result.expert)
        );

        if (onLogin) {
          onLogin(result.expert);
        }

      } else {

        alert(result.message);

      }

    } catch (error) {

      console.error(error);
      alert('Login failed');

    }

  };

  return (

    <div
      style={{
        maxWidth: '400px',
        margin: '50px auto',
        padding: '30px',
        border: '1px solid #ccc',
        borderRadius: '8px',
        background: '#fff'
      }}
    >

      <h2>Expert Login</h2>

      <form onSubmit={handleLogin}>

        <input
          type="email"
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
          style={{
            width: '100%',
            padding: '10px',
            marginBottom: '15px'
          }}
        />

        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
          style={{
            width: '100%',
            padding: '10px',
            marginBottom: '15px'
          }}
        />

        <button
          type="submit"
          style={{
            width: '100%',
            padding: '12px',
            background: '#004d40',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
            fontWeight: 'bold',
            cursor: 'pointer'
          }}
        >
          Login
        </button>

      </form>

    </div>

  );
}
